function out1 = RF_KuboTomita(T2b,sigtau,chems,w1,delta)% T2b is "t2" [s]% delta is sweep width [Hz]% sigtau is the product of sigma and tau (see paper below)% sigma^2*tau = R2b = 1/T2b% Normalized Kubo-Tomita function % Equation from Iino, MRM 1994, 32(4):459-63% Writted by D Korenchan, 2025% NOTE: Function deviates from Gaussian if sigtau > 3 (for T2b = 10e-6)Nsum=200;   %number of terms to use for infinite series (min 50; 200 seems             %to work fine within acceptable sigtau range)sig=1/T2b/sigtau;f4=0;for ii=0:(Nsum-1)    f1=((-1)^ii) / factorial(ii) * (sigtau)^(2*ii);    f2=sigtau + ii/(sigtau);    f3=f2^2 + (2*pi*(delta-chems)/sig).^2;    f4=f4 + f1*f2./f3;%     if mod(ii,5)==0%         figure; plot(delta,f4);%         figure; plot(delta,f1*f2./f3);%     endend%NOTE: The dividing factor of 4 in Iino, MRM 1994 was removed, just as in %Li et al, MRM 1997. With the factor of 4 removed, the Lorentzian and %Gaussian curves (as sig*tau << 1 and sig*tau >> 1, respectively) match the%corresponding equations in the literature (e.g. in Henkelman et al 1995).f5=f4./pi./sig*exp((sigtau)^2);            %out1=pi*(w1.^2).*f5; %add RF w1 saturation